const envelope = $json.body ?? $json;
const payload = envelope.payload ?? envelope;
const search = payload.search ?? {};
const callback = payload.callback ?? envelope.callback ?? {};

function text(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value).trim();
}

function integer(value, fallback, min = 0, max = 99999) {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.min(max, parsed));
}

function boolean(value, fallback = false) {
  if (value === true || value === false) return value;
  const normalized = text(value).toLowerCase();
  if (['1', 'true', 'sim', 'yes', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'nao', 'não', 'no', 'off'].includes(normalized)) return false;
  return fallback;
}

function modality(value) {
  const normalized = text(value).toLowerCase();
  if (['online', 'on-line', 'virtual', 'remoto'].includes(normalized)) return 'online';
  if (['presencial', 'in_person', 'in-person'].includes(normalized)) return 'presencial';
  return 'indefinida';
}

function normalizedOffset(value) {
  const offset = text(value, '-03:00');
  return /^[+-]\d{2}:\d{2}$/.test(offset) ? offset : '-03:00';
}

function toIso(value, offset) {
  const source = text(value);
  if (!source) return '';
  if (/Z$|[+-]\d{2}:\d{2}$/.test(source)) return new Date(source).toISOString();
  return new Date(`${source.replace(' ', 'T')}${offset}`).toISOString();
}

const action = text(payload.action, 'search').toLowerCase();
if (!['search', 'hold', 'confirm', 'release'].includes(action)) {
  throw new Error('action deve ser search, hold, confirm ou release.');
}

const utcOffset = normalizedOffset(search.utc_offset || payload.google_utc_offset || '-03:00');
const calendarId = text(payload.calendar_id || search.calendar_id, 'primary');
const encodedCalendar = encodeURIComponent(calendarId);
const googleEventId = text(payload.google_event_id || payload.event_id);
const startAt = text(search.start_at || payload.search_start_at);
const endAt = text(search.end_at || payload.search_end_at);
const windowStartIso = action === 'search' ? toIso(startAt, utcOffset) : '';
const windowEndIso = action === 'search' ? toIso(endAt, utcOffset) : '';

if (action === 'search' && (!windowStartIso || !windowEndIso)) {
  throw new Error('A janela de busca é obrigatória.');
}
if (action !== 'search' && !googleEventId) {
  throw new Error('google_event_id é obrigatório para atualizar o evento.');
}

const googleListUrl = action === 'search'
  ? `https://www.googleapis.com/calendar/v3/calendars/${encodedCalendar}/events?singleEvents=true&orderBy=startTime&showDeleted=false&maxResults=2500&timeMin=${encodeURIComponent(windowStartIso)}&timeMax=${encodeURIComponent(windowEndIso)}`
  : '';
const googleEventUrl = googleEventId
  ? `https://www.googleapis.com/calendar/v3/calendars/${encodedCalendar}/events/${encodeURIComponent(googleEventId)}`
  : '';

return [{
  json: {
    action,
    is_search: action === 'search',
    tenant_id: Number(payload.tenant_id || envelope.tenant_id || 0),
    appointment_id: payload.appointment_id ? Number(payload.appointment_id) : null,
    conversation_id: payload.conversation_id ? Number(payload.conversation_id) : null,
    contact_id: payload.contact_id ? Number(payload.contact_id) : null,
    request_id: Number(payload.request_id || 0),
    request_token: text(payload.request_token || callback.token),
    callback_url: text(callback.url, 'https://rsconnect.rsautomacaodigital.cloud/webhooks/calendar/availability'),
    calendar_id: calendarId,
    google_event_id: googleEventId,
    google_event_etag: text(payload.google_event_etag),
    google_list_url: googleListUrl,
    google_event_url: googleEventUrl,
    timezone: text(search.timezone || payload.timezone, 'America/Sao_Paulo'),
    utc_offset: utcOffset,
    window_start_iso: windowStartIso,
    window_end_iso: windowEndIso,
    max_suggestions: integer(search.max_suggestions, 5, 1, 200),
    online_title: text(search.marked_online_title || payload.online_title, 'VAGO — ONLINE'),
    in_person_title: text(search.marked_in_person_title || payload.in_person_title, 'VAGO — PRESENCIAL'),
    hold_prefix: text(payload.hold_prefix, 'PRÉ-RESERVADO'),
    confirmed_prefix: text(payload.confirmed_prefix, 'AGENDADO'),
    require_transparent: boolean(search.marked_require_transparent ?? payload.require_transparent, true),
    revalidate_before_update: boolean(payload.revalidate_before_update, true),
    requested_modality: modality(payload.modality || payload.preference?.modality),
    customer_name: text(payload.customer_name || payload.appointment?.contact_name, 'Cliente'),
    customer_phone: text(payload.customer_phone || payload.appointment?.phone),
    notes: text(payload.notes || payload.appointment?.description),
    original_summary: text(payload.original_summary),
    original_description: text(payload.original_description),
    original_transparency: text(payload.original_transparency, 'transparent'),
    original: envelope
  }
}];

const cfg = $('Normalizar operação').first().json;
const response = $json ?? {};
const events = Array.isArray(response.items) ? response.items : [];

function normalizeTitle(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[–—−]/g, '-')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();
}

function offsetMinutes(offset) {
  const sign = offset.startsWith('-') ? -1 : 1;
  const [hours, minutes] = offset.slice(1).split(':').map(Number);
  return sign * ((hours || 0) * 60 + (minutes || 0));
}

const offset = offsetMinutes(cfg.utc_offset);
function localSql(date) {
  const shifted = new Date(date.getTime() + offset * 60000);
  return shifted.toISOString().slice(0, 19).replace('T', ' ');
}
function localLabel(date) {
  const shifted = new Date(date.getTime() + offset * 60000);
  const iso = shifted.toISOString();
  return `${iso.slice(8, 10)}/${iso.slice(5, 7)}/${iso.slice(0, 4)} ${iso.slice(11, 16)}`;
}
function eventDate(value) {
  if (!value) return null;
  if (value.dateTime) return new Date(value.dateTime);
  if (value.date) return new Date(`${value.date}T00:00:00${cfg.utc_offset}`);
  return null;
}

const onlineTitle = normalizeTitle(cfg.online_title);
const inPersonTitle = normalizeTitle(cfg.in_person_title);
const slots = [];
let titleMatches = 0;
let transparencyRejected = 0;
let modalityRejected = 0;
let invalidDates = 0;

for (const event of events) {
  if (!event || String(event.status || '').toLowerCase() === 'cancelled') continue;
  const summary = String(event.summary || '');
  const normalized = normalizeTitle(summary);
  let modality = 'indefinida';
  if (normalized === onlineTitle) modality = 'online';
  if (normalized === inPersonTitle) modality = 'presencial';
  if (modality === 'indefinida') continue;
  titleMatches++;
  if (cfg.requested_modality !== 'indefinida' && cfg.requested_modality !== modality) {
    modalityRejected++;
    continue;
  }

  const transparency = String(event.transparency || 'opaque').toLowerCase();
  if (cfg.require_transparent && transparency !== 'transparent') {
    transparencyRejected++;
    continue;
  }

  const start = eventDate(event.start);
  const end = eventDate(event.end);
  if (!start || !end || Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
    invalidDates++;
    continue;
  }

  slots.push({
    start: localSql(start),
    end: localSql(end),
    label: `${localLabel(start)} · ${modality === 'online' ? 'Online' : 'Presencial'}`,
    modality,
    google_event_id: event.id || null,
    google_event_etag: event.etag || null,
    google_calendar_id: cfg.calendar_id,
    event_summary: summary,
    event_description: event.description || '',
    event_transparency: transparency,
    source: 'google_marked_slots'
  });
}

slots.sort((a, b) => a.start.localeCompare(b.start));
const limited = slots.slice(0, cfg.max_suggestions);
const callbackPayload = {
  event: 'calendar.availability.result',
  ok: true,
  tenant_id: cfg.tenant_id,
  appointment_id: cfg.appointment_id,
  request_id: cfg.request_id,
  request_token: cfg.request_token,
  source: 'google_marked_slots',
  google_calendar_id: cfg.calendar_id,
  slots: limited,
  meta: {
    online_title: cfg.online_title,
    in_person_title: cfg.in_person_title,
    require_transparent: cfg.require_transparent,
    events_read: events.length,
    title_matches: titleMatches,
    transparency_rejected: transparencyRejected,
    modality_rejected: modalityRejected,
    invalid_dates: invalidDates,
    slots_returned: limited.length
  }
};

return [{ json: { ...cfg, slots: limited, callback_payload: callbackPayload } }];

const cfg = $('Normalizar operação').first().json;
const event = $json ?? {};

function normalizeTitle(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[–—−]/g, '-')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();
}

function inferModality(summary) {
  const title = normalizeTitle(summary);
  if (title.includes('PRESENCIAL')) return 'presencial';
  if (title.includes('ONLINE')) return 'online';
  return cfg.requested_modality !== 'indefinida' ? cfg.requested_modality : 'online';
}

const currentSummary = String(event.summary || '');
const normalizedCurrent = normalizeTitle(currentSummary);
const onlineTitle = normalizeTitle(cfg.online_title);
const inPersonTitle = normalizeTitle(cfg.in_person_title);
const holdPrefix = normalizeTitle(cfg.hold_prefix);
const confirmedPrefix = normalizeTitle(cfg.confirmed_prefix);
const privateProps = event.extendedProperties?.private || {};
const modality = privateProps.rs_connect_modality || inferModality(currentSummary);
const modalityLabel = modality === 'presencial' ? 'PRESENCIAL' : 'ONLINE';
const currentTenant = String(privateProps.rs_connect_tenant_id || '');
const currentAppointment = String(privateProps.rs_connect_appointment_id || '');

if (cfg.action === 'hold') {
  if (![onlineTitle, inPersonTitle].includes(normalizedCurrent)) {
    throw new Error('O evento não está mais marcado como VAGO. Faça uma nova busca.');
  }
  if (cfg.require_transparent && String(event.transparency || 'opaque').toLowerCase() !== 'transparent') {
    throw new Error('O evento VAGO não está definido como Disponível/transparent.');
  }
}

if (cfg.action === 'confirm') {
  if (!normalizedCurrent.startsWith(holdPrefix)) {
    throw new Error('Somente um evento PRÉ-RESERVADO pode ser confirmado.');
  }
  if (currentTenant && currentTenant !== String(cfg.tenant_id)) throw new Error('O evento pertence a outra empresa do RS Connect.');
  if (currentAppointment && currentAppointment !== String(cfg.appointment_id)) throw new Error('O evento pertence a outro pré-agendamento.');
}

if (cfg.action === 'release') {
  const releasable = normalizedCurrent.startsWith(holdPrefix) || normalizedCurrent.startsWith(confirmedPrefix);
  if (!releasable) throw new Error('O evento não está pré-reservado ou agendado.');
  if (currentTenant && currentTenant !== String(cfg.tenant_id)) throw new Error('O evento pertence a outra empresa do RS Connect.');
  if (currentAppointment && currentAppointment !== String(cfg.appointment_id)) throw new Error('O evento pertence a outro pré-agendamento.');
}

const storedOriginalSummary = privateProps.rs_connect_original_summary || cfg.original_summary || (modality === 'presencial' ? cfg.in_person_title : cfg.online_title);
const storedOriginalDescription = privateProps.rs_connect_original_description ?? cfg.original_description ?? '';
const storedOriginalTransparency = privateProps.rs_connect_original_transparency || cfg.original_transparency || 'transparent';

let state;
let summary;
let description;
let transparency;
let extendedPrivate;

if (cfg.action === 'hold') {
  state = 'held';
  summary = `${cfg.hold_prefix} — ${modalityLabel} — ${cfg.customer_name}`;
  description = [
    'Origem: RS Connect',
    `Cliente: ${cfg.customer_name}`,
    cfg.customer_phone ? `Telefone: ${cfg.customer_phone}` : '',
    cfg.appointment_id ? `Pré-agendamento: #${cfg.appointment_id}` : '',
    cfg.conversation_id ? `Conversa: #${cfg.conversation_id}` : '',
    `Modalidade: ${modalityLabel}`,
    'Status: Pré-reservado',
    cfg.notes ? `Observações: ${cfg.notes}` : ''
  ].filter(Boolean).join('\n');
  transparency = 'opaque';
  extendedPrivate = {
    rs_connect_tenant_id: String(cfg.tenant_id || ''),
    rs_connect_request_id: String(cfg.request_id || ''),
    rs_connect_appointment_id: String(cfg.appointment_id || ''),
    rs_connect_state: state,
    rs_connect_modality: modality,
    rs_connect_original_summary: currentSummary || storedOriginalSummary,
    rs_connect_original_description: String(event.description || storedOriginalDescription).slice(0, 900),
    rs_connect_original_transparency: String(event.transparency || storedOriginalTransparency)
  };
} else if (cfg.action === 'confirm') {
  state = 'confirmed';
  summary = `${cfg.confirmed_prefix} — ${modalityLabel} — ${cfg.customer_name}`;
  description = String(event.description || '').replace('Status: Pré-reservado', 'Status: Agendado');
  transparency = 'opaque';
  extendedPrivate = { ...privateProps, rs_connect_state: state };
} else {
  state = 'released';
  summary = storedOriginalSummary;
  description = storedOriginalDescription;
  transparency = storedOriginalTransparency === 'opaque' ? 'opaque' : 'transparent';
  extendedPrivate = {
    rs_connect_state: 'available',
    rs_connect_modality: modality
  };
}

return [{
  json: {
    ...cfg,
    original_event: event,
    resolved_modality: modality,
    target_state: state,
    google_etag: event.etag || cfg.google_event_etag || '',
    patch_body: {
      summary,
      description,
      transparency,
      extendedProperties: { private: extendedPrivate }
    }
  }
}];

const cfg = $('Validar e preparar atualização').first().json;
const event = $json ?? {};

function offsetMinutes(offset) {
  const sign = offset.startsWith('-') ? -1 : 1;
  const [hours, minutes] = offset.slice(1).split(':').map(Number);
  return sign * ((hours || 0) * 60 + (minutes || 0));
}
const offset = offsetMinutes(cfg.utc_offset);
function localSqlFromGoogle(value) {
  const raw = value?.dateTime || value?.date || '';
  if (!raw) return null;
  const date = value?.dateTime ? new Date(raw) : new Date(`${raw}T00:00:00${cfg.utc_offset}`);
  if (Number.isNaN(date.getTime())) return null;
  const shifted = new Date(date.getTime() + offset * 60000);
  return shifted.toISOString().slice(0, 19).replace('T', ' ');
}

const callbackPayload = {
  event: 'calendar.marked_slot.updated',
  ok: true,
  tenant_id: cfg.tenant_id,
  appointment_id: cfg.appointment_id,
  request_id: cfg.request_id,
  request_token: cfg.request_token,
  source: 'google_marked_slots',
  action: cfg.action,
  state: cfg.target_state,
  google_event_id: event.id || cfg.google_event_id,
  google_calendar_id: cfg.calendar_id,
  modality: cfg.resolved_modality,
  start: localSqlFromGoogle(event.start || cfg.original_event?.start),
  end: localSqlFromGoogle(event.end || cfg.original_event?.end),
  previous_summary: cfg.original_event?.summary || '',
  current_summary: event.summary || cfg.patch_body.summary,
  transparency: event.transparency || cfg.patch_body.transparency,
  updated_at: new Date().toISOString()
};

return [{ json: { ...cfg, updated_event: event, callback_payload: callbackPayload } }];
